-                            current.netmask = IPv4Address.fromInt(mask);
-                            current.hostmask = IPv4Address.fromInt(~mask);
-                            break;
-                        }
-                        new_prefix -= 1;
-                    }
-                }
-                i += 1;
-            } else {
-                break;
-            }
-        }
-
-        try result.append(current);
