-        }
-
-        /// Get flags from info string
-        pub fn getFlags(self: *MaildirMessage) []const u8 {
-            if (std.mem.indexOf(u8, self.info, "2,")) |idx| {
-                return self.info[idx + 2 ..];
-            }
