-                var new_flags: [6]u8 = undefined;
-                var count: usize = 0;
-                for (info) |c| {
-                    if (std.ascii.isUpper(c) and c != upper) {
-                        new_flags[count] = c;
-                        count += 1;
-                    }
-                }
-                if (count > 0) {
-                    self.setFlags(new_flags[0..count]);
-                } else {
-                    self.info = "2,";
-                }
-            }
-        }
-    };
