+    var lock = Lock.init();
+
+    try std.testing.expect(lock.acquire(false, null));
+    try std.testing.expect(!lock.acquire(false, null)); // Already locked
+    lock.release();
+    try std.testing.expect(lock.acquire(false, null)); // Now available
+    lock.release();
